class Solution:
    def lastSubstring(self, s: str) -> str:
        n = len(s)
        max_str = ""
        for i in range(n):
            for j in range(i + 1, n + 1):
                substr = s[i:j]
                if substr > max_str:
                    max_str = substr
        return max_str
